// Validate inbound payload. Throws → n8n returns 500 (rejected).
const body = $input.item.json.body || $input.item.json;
const message = (body.message || '').toString().trim();
const session_id = (body.session_id || 'default').toString().slice(0, 64);
const user_id = (body.user_id || $input.item.json.headers?.['x-user-id'] || 'user_1').toString().slice(0, 64);

if (!message) throw new Error('VALIDATE: message is required');
if (message.length > 2000) throw new Error('VALIDATE: message too long (max 2000 chars)');
if (!/^user_[0-9]+$/.test(user_id)) throw new Error('VALIDATE: invalid user_id format');

return { json: { message, session_id, user_id, received_at: new Date().toISOString() } };

// Token-bucket rate limiter: 30 messages per user per minute.
// Uses n8n's persistent static data store.
const userId = $input.item.json.user_id;
const now = Date.now();
const windowMs = 60_000;
const limit = 30;

const data = $getWorkflowStaticData('global');
data.buckets = data.buckets || {};
const bucket = data.buckets[userId] || { count: 0, reset_at: now + windowMs };
if (now > bucket.reset_at) { bucket.count = 0; bucket.reset_at = now + windowMs; }
bucket.count += 1;
data.buckets[userId] = bucket;

if (bucket.count > limit) {
  const retryAfter = Math.ceil((bucket.reset_at - now) / 1000);
  throw new Error(`RATE_LIMIT: ${limit}/min exceeded for ${userId} (retry in ${retryAfter}s)`);
}
return $input.item;

// Audit log: structured record of every chat. n8n persists this in
// execution_data - reviewable via UI / API / SQLite directly.
const input = $('Validate Input').item.json;
const out = $input.item.json;
const event = {
  ts: new Date().toISOString(),
  execution_id: $execution.id,
  user_id: input.user_id,
  session_id: input.session_id,
  query: (input.message || '').slice(0, 200),
  route: out && out.structured_data && out.structured_data.route,
  rationale: (out && out.structured_data && out.structured_data.rationale || '').slice(0, 200),
  tools_called: ((out && out.tool_calls) || []).map(t => t.name),
  citations_count: ((out && out.citations) || []).length,
  response_chars: (out && out.message || '').length,
};
console.log('FINSIGHT_AUDIT', JSON.stringify(event));
// Pass the agent response through unchanged - this is the workflow's final output.
return $input.item;
